CREATE OR REPLACE FUNCTION OFSERM.DERIVATIVE_UNDERLYING_DATA_POP(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FSI_CAP_DERIVATIVES(N_MIS_DATE_SKEY,N_ACCT_SKEY,N_EXP_SENIORITY,N_BRANCH_SKEY,N_D_CUST_INDUSTRY_SKEY,F_REG_CAP_INVST_IND,N_INSTRUMENT_SKEY,N_ISSUE_SKEY,F_CORE_INVESTMENT_COMPANY_IND,F_FINANCIAL_ENTITY_IND,F_REGULATED_FIN_ENTITY_IND,N_COUNTERPARTY_TYPE_SKEY,N_PROD_SKEY,F_SECURITIZED_FLAG,N_REMARGIN_FREQUENCY,N_REVALUATION_FREQUENCY,F_REGULATORY_PARTY_INDICATOR,N_COUNTRY_SKEY,N_CUST_SKEY,N_EXCHANGE_RATE,N_EXPOSURE_AMOUNT,N_GAAP_SKEY,N_GROUP_ASSET_SIZE,N_ORIGINAL_MATURITY,N_PARENT_ACCT_SKEY,N_RESIDUAL_MATURITY,N_RUN_SKEY,N_CUST_ANNUAL_SALES,N_SHAREHOLDING_PERCENT,V_APPROACH_TYPE,V_CCY_CODE,V_DATA_SOURCE,V_EXP_RCY_CODE,V_UNDERLYING_DATA_IDENTIFIER,N_ENTITY_SKEY,N_LOAD_RUN_ID,N_CAP_APPROACH_TYPE_SKEY,N_CAP_RECORD_TYPE_SKEY,V_RECORD_TYPE,N_STD_COUNTERPARTY_TYPE_SKEY,N_BASEL_TXN_TYPE_SKEY,N_REG_CAP_INDUSTRY_SKEY,N_REG_INDUSTRY_SKEY,N_BASEL_PROD_TYPE_SKEY,N_STD_SENIORITY_SKEY,N_ADJUSTED_LGD_PERCENT,N_EFF_MATURITY,N_LGD_PERCENT_PRE_CRM,N_PD_PERCENT,N_SEC_POOL_SKEY)SELECT  /*+PARALLEL (4)*/ to_char(DIM_DATES.N_DATE_SKEY),to_char(DIM_EXPOSURE.N_ACCT_SKEY),to_char(DIM_EXPOSURE_SENIORITY.N_EXP_SENIORITY),to_char(DIM_GEOGRAPHY.N_BRANCH_SKEY),to_char(DIM_INDUSTRY.N_D_CUST_INDUSTRY_SKEY),DIM_INSTRUMENT_CONTRACT.F_REG_CAP_INVST_IND,to_char(DIM_INSTRUMENT_CONTRACT.N_INSTRUMENT_SKEY),to_char(DIM_ISSUE.N_ISSUE_SKEY),DIM_PARTY.F_CORE_INVESTMENT_COMPANY_IND,DIM_PARTY.F_FINANCIAL_ENTITY_IND,DIM_PARTY.F_REGULATED_FIN_ENTITY_IND,to_char(DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY),to_char(DIM_PRODUCT.N_PROD_SKEY),DIM_UNDERLYING.F_SECURITIZED_FLAG,to_char(DIM_UNDERLYING.N_REMARGIN_FREQUENCY),to_char(DIM_UNDERLYING.N_REVALUATION_FREQUENCY),DIM_ORG_STRUCTURE_REG.F_REGULATORY_ENTITY_IND,FCT_ENTITY_INFO_CUST.N_COUNTRY_SKEY,DIM_PARTY_CUST.N_PARTY_SKEY,FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_UNDERLYING_DTL.N_BOOK_VALUE * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,FCT_ENTITY_INFO_CUST.N_GAAP_SKEY,FSI_CAP_PARTY_FINANCIALS.N_GROUP_ASSET_SIZE * B_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,DAYS_BETWEEN(DIM_INSTRUMENT_CONTRACT.D_MATURITY_DATE,DIM_INSTRUMENT_CONTRACT.D_ISSUE_DATE,DIM_INSTRUMENT_CONTRACT.V_DAY_COUNTER),DIM_PARENT_EXPOSURE.N_ACCT_SKEY,DAYS_BETWEEN(to_date('20260331','YYYYMMDD'),DIM_UNDERLYING.d_underlying_maturity_date,COALESCE (DIM_UNDERLYING.V_DAY_COUNT_IND_PAY, DIM_UNDERLYING.V_DAY_COUNT_IND_RCV)),'870',FSI_CAP_PARTY_FINANCIALS.N_SALES_AMT* A_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN DIM_BASEL_CAP_CONSL_APPR.V_BASEL_CAP_CONSL_APPR_CODE = 'PRCS' THEN FCT_ENTITY_INFO.N_SHAREHOLDING_PERCENT ELSE 1 END,FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE,COALESCE (DIM_UNDERLYING.V_RCV_CCY,DIM_UNDERLYING.V_PAY_CCY),'DIM_UNDERLYING',RUN_EXE_PARAMETERS_RCY.V_PARAM_VALUE_CODE,'CIU',to_char(FCT_ENTITY_INFO.N_ENTITY_SKEY),to_char(FSI_CAP_ACCOUNT_LOAD_RUN_MAP.N_LOAD_RUN_ID),to_char(FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY),to_char(FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY),FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE,to_char(FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY),to_char(FSI_PROD_TXN_TYPE_RECLASS.N_BASEL_TXN_TYPE_SKEY),to_char(FSI_REG_CAP_INDUSTRY_RECLASS.N_REG_CAP_INDUSTRY_SKEY),to_char(FSI_REG_INDUSTRY_RECLASS.N_REG_INDUSTRY_SKEY),to_char(FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY),to_char(FSI_SENIORITY_RECLASSIFICATION.N_STD_SENIORITY_SKEY),to_char(FSI_UNDERLYING_MODELING_INFO.N_ADJUSTED_LGD_PERCENT),to_char(FSI_UNDERLYING_MODELING_INFO.N_EFF_MATURITY),to_char(FSI_UNDERLYING_MODELING_INFO.N_LGD_PERCENT),to_char(FSI_UNDERLYING_MODELING_INFO.N_PD_PERCENT),to_char(SEC_POOL_MASTER.N_SEC_POOL_SKEY) FROM DIM_UNDERLYING INNER JOIN DIM_DATES ON DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') AND to_date('20260331','YYYYMMDD') BETWEEN DIM_UNDERLYING.D_RECORD_START_DATE AND DIM_UNDERLYING.D_RECORD_END_DATE INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = '870' INNER JOIN DIM_EXPOSURE ON DIM_UNDERLYING.V_UNDERLYING_CODE = DIM_EXPOSURE.V_EXPOSURE_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_EXPOSURE.D_RECORD_START_DATE AND DIM_EXPOSURE.D_RECORD_END_DATE INNER JOIN FCT_ENTITY_INFO ON DIM_UNDERLYING.V_LV_CODE = FCT_ENTITY_INFO.V_ENTITY_CODE AND FCT_ENTITY_INFO.N_RUN_SKEY = '870' LEFT OUTER JOIN STG_UNDERLYING_DTL ON STG_UNDERLYING_DTL.FIC_MIS_DATE = to_date('20260331','YYYYMMDD') AND COALESCE(STG_UNDERLYING_DTL.V_INSTRUMENT_CODE,DIM_EXPOSURE.V_EXPOSURE_ID) = DIM_UNDERLYING.V_UNDERLYING_CODE LEFT OUTER JOIN FSI_UNDERLYING_MODELING_INFO ON DIM_UNDERLYING.V_UNDERLYING_CODE = FSI_UNDERLYING_MODELING_INFO.V_UNDERLYING_CODE LEFT OUTER JOIN DIM_ISSUE ON DIM_UNDERLYING.V_UNDERLYING_CODE = DIM_ISSUE.V_ISSUE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ISSUE.D_RECORD_START_DATE AND DIM_ISSUE.D_RECORD_END_DATE LEFT OUTER JOIN DIM_PRODUCT ON DIM_UNDERLYING.V_PROD_CODE = DIM_PRODUCT.V_PROD_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PRODUCT.D_RECORD_START_DATE AND DIM_PRODUCT.D_RECORD_END_DATE LEFT OUTER JOIN DIM_INSTRUMENT_CONTRACT DIM_INSTRUMENT_CONTRACT_P ON DIM_INSTRUMENT_CONTRACT_P.V_INSTRUMENT_CODE = STG_UNDERLYING_DTL.V_CONTRACT_INSTRUMENT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_INSTRUMENT_CONTRACT_P.D_RECORD_START_DATE AND DIM_INSTRUMENT_CONTRACT_P.D_RECORD_END_DATE LEFT OUTER JOIN ( SELECT MAX(N_ACCT_SKEY) N_ACCT_SKEY ,N_GAAP_SKEY ,N_LOAD_RUN_ID ,N_INSTRUMENT_SKEY FROM FSI_CAP_INVESTMENT_EXPOSURES WHERE N_RUN_SKEY = '870' GROUP BY N_GAAP_SKEY ,N_LOAD_RUN_ID ,N_INSTRUMENT_SKEY ) DIM_PARENT_EXPOSURE ON DIM_PARENT_EXPOSURE.N_INSTRUMENT_SKEY = DIM_INSTRUMENT_CONTRACT_P.N_INSTRUMENT_SKEY INNER JOIN FSI_CAP_ACCOUNT_LOAD_RUN_MAP ON DIM_PARENT_EXPOSURE.N_ACCT_SKEY = FSI_CAP_ACCOUNT_LOAD_RUN_MAP.N_ACCT_SKEY AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.FIC_MIS_DATE = to_date('20260331','YYYYMMDD') AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.N_GAAP_SKEY = DIM_PARENT_EXPOSURE.N_GAAP_SKEY AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.N_RUN_SKEY = '870' LEFT OUTER JOIN DIM_PARTY ON COALESCE(DIM_UNDERLYING.V_ISSUER_CODE, 'MSG') = DIM_PARTY.V_PARTY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY.D_RECORD_START_DATE AND DIM_PARTY.D_RECORD_END_DATE INNER JOIN DIM_PARTY_TYPE ON COALESCE(DIM_PARTY.V_PARTY_TYPE, 'MSG') = DIM_PARTY_TYPE.V_PARTY_TYPE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY_TYPE.D_RECORD_START_DATE AND DIM_PARTY_TYPE.D_RECORD_END_DATE LEFT OUTER JOIN DIM_PARTY DIM_PARTY_CUST ON DIM_UNDERLYING.V_CUST_REF_CODE = DIM_PARTY_CUST.V_PARTY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY_CUST.D_RECORD_START_DATE AND DIM_PARTY_CUST.D_RECORD_END_DATE INNER JOIN DIM_BASEL_CAP_CONSL_APPR ON DIM_BASEL_CAP_CONSL_APPR.N_BASEL_CAP_CONSL_APPR_SKEY = FCT_ENTITY_INFO.N_BASEL_CAP_CONSL_APPR_SKEY LEFT OUTER JOIN DIM_GEOGRAPHY ON COALESCE(DIM_PARTY.V_BRANCH_CODE, 'MSG') = DIM_GEOGRAPHY.V_ACCT_BRANCH_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_GEOGRAPHY.D_RECORD_START_DATE AND DIM_GEOGRAPHY.D_RECORD_END_DATE LEFT OUTER JOIN DIM_INDUSTRY ON DIM_INDUSTRY.V_D_CUST_INDUSTRY = COALESCE(DIM_PARTY.V_INDUSTRY_CODE, 'MSG') AND to_date('20260331','YYYYMMDD') BETWEEN DIM_INDUSTRY.D_RECORD_START_DATE AND DIM_INDUSTRY.D_RECORD_END_DATE LEFT OUTER JOIN FSI_CAP_PARTY_FINANCIALS ON FSI_CAP_PARTY_FINANCIALS.N_RUN_SKEY = '870' AND FSI_CAP_PARTY_FINANCIALS.N_PARTY_SKEY = DIM_PARTY.N_PARTY_SKEY LEFT OUTER JOIN RUN_EXE_PARAMETERS ON RUN_EXE_PARAMETERS.N_RUN_SKEY = '870' AND RUN_EXE_PARAMETERS.V_PARAM_ID = 'LE' INNER JOIN DIM_ORG_STRUCTURE ON DIM_ORG_STRUCTURE.V_ENTITY_CODE = RUN_EXE_PARAMETERS.V_PARAM_VALUE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ORG_STRUCTURE.D_RECORD_START_DATE AND DIM_ORG_STRUCTURE.D_RECORD_END_DATE LEFT OUTER JOIN RUN_EXE_PARAMETERS RUN_EXE_PARAMETERS_RCY ON RUN_EXE_PARAMETERS_RCY.N_RUN_SKEY = '870' AND RUN_EXE_PARAMETERS_RCY.V_PARAM_ID = 'RCY' LEFT OUTER JOIN DIM_LOCATION ON DIM_LOCATION.V_LOCATION_CODE = DIM_PARTY.V_LOCATION_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_LOCATION.D_RECORD_START_DATE AND DIM_LOCATION.D_RECORD_END_DATE LEFT OUTER JOIN FSI_REG_PROD_TYPE_RECLASS ON FSI_REG_PROD_TYPE_RECLASS.N_RUN_SKEY = '870' AND FSI_REG_PROD_TYPE_RECLASS.N_PROD_SKEY = DIM_PRODUCT.N_PROD_SKEY LEFT OUTER JOIN DIM_BASEL_PRODUCT_TYPE ON DIM_BASEL_PRODUCT_TYPE.N_BASEL_PROD_TYPE_SKEY = FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY LEFT OUTER JOIN FSI_PARTY_TYPE_CLASSIFICATION ON FSI_PARTY_TYPE_CLASSIFICATION.N_RUN_SKEY = '870' AND FSI_PARTY_TYPE_CLASSIFICATION.N_PARTY_TYPE_SKEY = DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY LEFT OUTER JOIN DIM_INSTRUMENT_CONTRACT ON DIM_INSTRUMENT_CONTRACT.V_INSTRUMENT_CODE = STG_UNDERLYING_DTL.V_INSTRUMENT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_INSTRUMENT_CONTRACT.D_RECORD_START_DATE AND DIM_INSTRUMENT_CONTRACT.D_RECORD_END_DATE LEFT OUTER JOIN FCT_INSTRUMENT_CONTRACT_DTL ON FCT_INSTRUMENT_CONTRACT_DTL.N_INSTRUMENT_SKEY = DIM_INSTRUMENT_CONTRACT.N_INSTRUMENT_SKEY AND FCT_INSTRUMENT_CONTRACT_DTL.N_RUN_SKEY = '870' LEFT OUTER JOIN SEC_POOL_MASTER ON SEC_POOL_MASTER.V_SEC_POOL_ID = STG_UNDERLYING_DTL.V_INSTRUMENT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN COALESCE(SEC_POOL_MASTER.D_RECORD_START_DATE, to_date('20260331','YYYYMMDD')) AND COALESCE(SEC_POOL_MASTER.D_RECORD_END_DATE, to_date('20260331','YYYYMMDD')) LEFT OUTER JOIN DIM_EXPOSURE_SENIORITY ON DIM_EXPOSURE_SENIORITY.V_SENIORITY_CODE = DIM_UNDERLYING.V_EXP_SENIORITY_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_EXPOSURE_SENIORITY.D_RECORD_START_DATE AND DIM_EXPOSURE_SENIORITY.D_RECORD_END_DATE LEFT OUTER JOIN FSI_CAP_CURRENCY_CONVERSION ON DIM_RUN.N_RUN_SKEY = FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = COALESCE(DIM_UNDERLYING.V_RCV_CCY, DIM_UNDERLYING.V_PAY_CCY) LEFT OUTER JOIN FSI_CAP_CURRENCY_CONVERSION A_FSI_CAP_CURRENCY_CONVERSION ON DIM_RUN.N_RUN_SKEY = A_FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND A_FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = FSI_CAP_PARTY_FINANCIALS.V_CCY_CODE LEFT OUTER JOIN FSI_CAP_CURRENCY_CONVERSION B_FSI_CAP_CURRENCY_CONVERSION ON DIM_RUN.N_RUN_SKEY = B_FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND B_FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = FSI_CAP_PARTY_FINANCIALS.V_GROUP_CCY_CODE LEFT OUTER JOIN FSI_SENIORITY_RECLASSIFICATION ON FSI_SENIORITY_RECLASSIFICATION.N_SENIORITY = DIM_EXPOSURE_SENIORITY.N_EXP_SENIORITY AND FSI_SENIORITY_RECLASSIFICATION.N_RUN_SKEY = '870' LEFT OUTER JOIN FSI_PROD_TXN_TYPE_RECLASS ON FSI_PROD_TXN_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY = DIM_BASEL_PRODUCT_TYPE.N_BASEL_PROD_TYPE_SKEY AND FSI_PROD_TXN_TYPE_RECLASS.N_RUN_SKEY = '870' LEFT OUTER JOIN FSI_CAP_RUN_EXE_PARAMETERS ON FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY = '870' LEFT OUTER JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = '870' AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'NONSEC' LEFT OUTER JOIN RUN_PARAMETERS ON RUN_PARAMETERS.N_RUN_SKEY = '870' AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = RUN_PARAMETERS.N_RUN_PARAMETER_SKEY LEFT OUTER JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE = FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE LEFT OUTER JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'DRV_NON_SEC_ULY' LEFT OUTER JOIN DIM_ORG_STRUCTURE DIM_ORG_STRUCTURE_REG ON DIM_ORG_STRUCTURE_REG.V_ENTITY_CODE = DIM_UNDERLYING.V_LV_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ORG_STRUCTURE_REG.D_RECORD_START_DATE AND DIM_ORG_STRUCTURE_REG.D_RECORD_END_DATE LEFT OUTER JOIN FSI_REG_INDUSTRY_RECLASS ON FSI_REG_INDUSTRY_RECLASS.N_D_CUST_INDUSTRY_SKEY = DIM_INDUSTRY.N_D_CUST_INDUSTRY_SKEY AND FSI_REG_INDUSTRY_RECLASS.N_RUN_SKEY = '870' LEFT OUTER JOIN FCT_ENTITY_INFO FCT_ENTITY_INFO_CUST ON FCT_ENTITY_INFO_CUST.N_RUN_SKEY = '870' AND FCT_ENTITY_INFO_CUST.F_CAP_CONSL_PARENT_ENTITY_IND = 'Y' LEFT JOIN FSI_REG_CAP_INDUSTRY_RECLASS ON FSI_REG_CAP_INDUSTRY_RECLASS.N_D_CUST_INDUSTRY_SKEY = DIM_INDUSTRY.N_D_CUST_INDUSTRY_SKEY AND FSI_REG_CAP_INDUSTRY_RECLASS.N_RUN_SKEY = '870' WHERE 1=1 AND DIM_BASEL_PRODUCT_TYPE.V_BASEL_PROD_TYPE_CODE NOT IN ( 'EQ' ,'EQC' ,'UCT' ,'BOLI' ) AND DAYS_BETWEEN(to_date('20260331','YYYYMMDD'),DIM_UNDERLYING.d_underlying_maturity_date,COALESCE (DIM_UNDERLYING.V_DAY_COUNT_IND_PAY, DIM_UNDERLYING.V_DAY_COUNT_IND_RCV))>0 LOG ERRORS INTO FSI_CAP_DERIVATIVES$ ('1776768386890_83650263_20260331_1_Job_1583417049448') REJECT LIMIT 0;

    COMMIT;
    RETURN 'OK';

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RETURN 'FAIL: ' || SQLERRM;
END;
